SELECT d.*, ste.site_nm AS site_nm, cd_dt.code_label AS discnt_type_cd_nm, cd_dt2.code_label AS discnt_target_cd_nm, cd_ds.code_label AS discnt_status_cd_nm, cd_mg.code_label AS mem_grade_cd_nm FROM pm_discnt d LEFT JOIN sy_site ste ON ste.site_id = d.site_id LEFT JOIN sy_code cd_dt ON cd_dt.code_grp = 'DISCNT_TYPE' AND cd_dt.code_value = d.discnt_type_cd LEFT JOIN sy_code cd_dt2 ON cd_dt2.code_grp = 'DISCNT_TARGET' AND cd_dt2.code_value = d.discnt_target_cd LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DISCNT_STATUS' AND cd_ds.code_value = d.discnt_status_cd LEFT JOIN sy_code cd_mg ON cd_mg.code_grp = 'MEMBER_GRADE' AND cd_mg.code_value = d.mem_grade_cd
ORDER BY d.discnt_id ASC ORDER BY d.discnt_id DESC ORDER BY d.discnt_nm ASC ORDER BY d.discnt_nm DESC ORDER BY d.reg_date ASC ORDER BY d.reg_date DESC ORDER BY d.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT d.*, ste.site_nm AS site_nm, cd_dt.code_label AS discnt_type_cd_nm, cd_dt2.code_label AS discnt_target_cd_nm, cd_ds.code_label AS discnt_status_cd_nm, cd_mg.code_label AS mem_grade_cd_nm FROM pm_discnt d LEFT JOIN sy_site ste ON ste.site_id = d.site_id LEFT JOIN sy_code cd_dt ON cd_dt.code_grp = 'DISCNT_TYPE' AND cd_dt.code_value = d.discnt_type_cd LEFT JOIN sy_code cd_dt2 ON cd_dt2.code_grp = 'DISCNT_TARGET' AND cd_dt2.code_value = d.discnt_target_cd LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DISCNT_STATUS' AND cd_ds.code_value = d.discnt_status_cd LEFT JOIN sy_code cd_mg ON cd_mg.code_grp = 'MEMBER_GRADE' AND cd_mg.code_value = d.mem_grade_cd
ORDER BY d.discnt_id ASC ORDER BY d.discnt_id DESC ORDER BY d.discnt_nm ASC ORDER BY d.discnt_nm DESC ORDER BY d.reg_date ASC ORDER BY d.reg_date DESC ORDER BY d.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

