UPDATE pm_discnt
site_id = #{siteId}, discnt_nm = #{discntNm}, discnt_type_cd = #{discntTypeCd}, discnt_target_cd = #{discntTargetCd}, discnt_value = #{discntValue}, min_order_amt = #{minOrderAmt}, min_order_qty = #{minOrderQty}, max_discnt_amt = #{maxDiscntAmt}, start_date = #{startDate}, end_date = #{endDate}, discnt_status_cd = #{discntStatusCd}, discnt_status_cd_before = #{discntStatusCdBefore}, discnt_desc = #{discntDesc}, mem_grade_cd = #{memGradeCd}, self_cdiv_rate = #{selfCdivRate}, seller_cdiv_rate = #{sellerCdivRate}, dvc_pc_yn = #{dvcPcYn}, dvc_mweb_yn = #{dvcMwebYn}, dvc_mapp_yn = #{dvcMappYn}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE discnt_id = #{discntId}
